// Laravel ya extrajo el texto, solo preparamos los datos
const body = $input.first().json.body || $input.first().json;

const companySlug = body.company_slug || 'default';
const filename = body.filename || 'document.txt';
const category = body.category || 'general';
const text = body.text || '';
const openaiApiKey = body.openai_api_key || '';
const qdrantHost = body.qdrant_host || 'https://qdrant-production-f4e7.up.railway.app';
const qdrantApiKey = body.qdrant_api_key || '';

const collectionName = 'company_' + companySlug.replace(/[^a-z0-9_-]/gi, '_').toLowerCase() + '_knowledge';

if (!text || text.length < 50) {
  throw new Error('No se recibió texto válido del documento.');
}

return {
  json: {
    company_slug: companySlug,
    filename: filename,
    category: category,
    collection_name: collectionName,
    text: text,
    text_length: text.length,
    openai_api_key: openaiApiKey,
    qdrant_host: qdrantHost,
    qdrant_api_key: qdrantApiKey
  }
};

// Dividir texto en chunks - MÃXIMO 5000 chars para embeddings
const text = $input.first().json.text || '';
const companySlug = $input.first().json.company_slug;
const filename = $input.first().json.filename;
const category = $input.first().json.category;
const collectionName = $input.first().json.collection_name;
const openaiApiKey = $input.first().json.openai_api_key;
const qdrantHost = $input.first().json.qdrant_host;
const qdrantApiKey = $input.first().json.qdrant_api_key;

const maxCharsPerChunk = 5000;
const chunks = [];

if (text.length <= maxCharsPerChunk) {
  chunks.push(text);
} else {
  let remaining = text;
  while (remaining.length > 0) {
    if (remaining.length <= maxCharsPerChunk) {
      chunks.push(remaining.trim());
      break;
    }
    let cutPoint = maxCharsPerChunk;
    const searchStart = Math.max(0, maxCharsPerChunk - 500);
    const searchArea = remaining.substring(searchStart, maxCharsPerChunk);
    const lastPeriod = searchArea.lastIndexOf('. ');
    const lastNewline = searchArea.lastIndexOf('\n');
    const lastDoubleNewline = searchArea.lastIndexOf('\n\n');
    if (lastDoubleNewline > 0) {
      cutPoint = searchStart + lastDoubleNewline + 2;
    } else if (lastPeriod > 0) {
      cutPoint = searchStart + lastPeriod + 2;
    } else if (lastNewline > 0) {
      cutPoint = searchStart + lastNewline + 1;
    }
    const chunk = remaining.substring(0, cutPoint).trim();
    if (chunk) {
      chunks.push(chunk);
    }
    remaining = remaining.substring(cutPoint);
  }
}

return chunks.map((chunk, index) => ({
  json: {
    text: chunk,
    chunk_index: index,
    total_chunks: chunks.length,
    company_slug: companySlug,
    filename: filename,
    category: category,
    collection_name: collectionName,
    openai_api_key: openaiApiKey,
    qdrant_host: qdrantHost,
    qdrant_api_key: qdrantApiKey
  }
}));

const item = $input.first();
const embedding = item.json.data[0].embedding;
const prevData = $('Split into Chunks').item.json;

// ID ENTERO basado en timestamp + chunk_index
const timestamp = Date.now();
const chunkSuffix = prevData.chunk_index.toString().padStart(4, '0');
const pointId = parseInt(timestamp.toString() + chunkSuffix);

return {
  json: {
    id: pointId,
    vector: embedding,
    payload: {
      text: prevData.text,
      filename: prevData.filename,
      category: prevData.category,
      company_slug: prevData.company_slug,
      chunk_index: prevData.chunk_index,
      total_chunks: prevData.total_chunks,
      type: 'document',
      updated_at: new Date().toISOString()
    },
    collection_name: prevData.collection_name,
    qdrant_host: prevData.qdrant_host,
    qdrant_api_key: prevData.qdrant_api_key
  }
};

